from mcp.server.fastmcp import FastMCPimport aiohttp# Initialize FastMCP servermcp = FastMCP(name="Football Results",              instructions=("You are a football assistant that can fetch the latest match results for any club."))BASE_URL = "https://api-football-v1.p.rapidapi.com/v3"# Replace with your actual API key and base URLAPI_KEY = "..."headers = {    "x-rapidapi-host": "api-football-v1.p.rapidapi.com",    "x-rapidapi-key": API_KEY}async def make_http_request(url: str, headers: dict) -> dict:    async with aiohttp.ClientSession() as session:        async with session.get(url, headers=headers) as resp:            if resp.status != 200:                return None            return await resp.json()@mcp.tool()async def get_last_match_result(team_name: str) -> str:    """    Get the latest football match result for a given team name.    Args:        team_name: The name of the football team.    """    # Step 1: Get team ID from team name    team_search_url = f"{BASE_URL}/teams?search={team_name}"    team_data = await make_http_request(team_search_url, headers)    if not team_data or not team_data.get("response"):        return f"Could not find team named '{team_name}'."    team_id = team_data["response"][0]["team"]["id"]    # Step 2: Get last match result    fixtures_url = f"{BASE_URL}/fixtures?team={team_id}&last=1"    fixture_data = await make_http_request(fixtures_url, headers)    if not fixture_data or not fixture_data.get("response"):        return f"No recent matches found for team '{team_name}'."    match = fixture_data["response"][0]    home = match["teams"]["home"]["name"]    away = match["teams"]["away"]["name"]    score_home = match["goals"]["home"]    score_away = match["goals"]["away"]    date = match["fixture"]["date"]    result = f"""Date: {date}Match: {home} vs {away}Score: {score_home} - {score_away}Winner: {match['teams']['home']['winner'] and home or away}"""    return result.strip()if __name__ == "__main__":    # Initialize and run the server    mcp.run(transport='stdio')    